                        limitPrice: $limitPrice,
                        symbols: symbols,
                        quote: appState.market.quote(for: selectedSymbol),
                        onPlaceOrder: placeOrder
                    )
                }
                .frame(maxWidth: .infinity)

                VStack(spacing: 16) {
                    PositionsView(positions: appState.portfolioStore.portfolio.positions)
                    OpenOrdersView(orders: appState.portfolioStore.openOrders, onCancel: cancelOrder)
                }
                .frame(maxWidth: .infinity)
