            LinearGradient(
                colors: [Color.black, Color(red: 0.06, green: 0.08, blue: 0.14)],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            .ignoresSafeArea()
        )
        .alert("Trading", isPresented: $showingAlert) {
            Button("OK", role: .cancel) {}
        } message: {
            Text(alertMessage)
        }
        .task {
            await appState.tradeService?.loadPortfolio()
            await appState.tradeService?.loadOpenOrders()
        }
    }

    private func placeOrder() {
        guard let service = appState.tradeService else { return }
        guard let qty = Int(quantity), qty > 0 else {
            alertMessage = "Enter a valid quantity."
            showingAlert = true
            return
        }
        if selectedType == .limit, Double(limitPrice) == nil {
            alertMessage = "Enter a valid limit price."
            showingAlert = true
            return
        }

        isPlacingOrder = true
        Task {
            do {
                let order = OrderRequest(
                    symbol: selectedSymbol,
                    side: selectedSide,
                    quantity: qty,
                    type: selectedType,
                    limitPrice: selectedType == .limit ? Double(limitPrice) : nil
                )
                try await service.placeOrder(order)
                await MainActor.run {
                    alertMessage = "\(selectedSide.rawValue.capitalized) order submitted for \(qty) \(selectedSymbol)."
                    showingAlert = true
                    isPlacingOrder = false
                }
            } catch {
                await MainActor.run {
                    alertMessage = error.localizedDescription
                    showingAlert = true
                    isPlacingOrder = false
                }
            }
