        guard let service = appState.tradeService else { return }
        Task {
            do {
                try await service.cancelOrder(id: order.id)
            } catch {
                await MainActor.run {
                    alertMessage = error.localizedDescription
                    showingAlert = true
                }
            }
        }
    }
