enum OrderSide: String, Codable, CaseIterable {
    case buy
    case sell
}

enum OrderType: String, Codable, CaseIterable {
    case market
    case limit
}

struct OrderRequest: Codable {
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let limitPrice: Double?
}

struct TradeOrder: Identifiable, Codable {
    let id: String
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let type: OrderType
    let status: String
    let limitPrice: Double?
    let createdAt: Date
}

struct Execution: Identifiable, Codable {
    let id: String
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let price: Double
    let timestamp: Date

    var notional: Double { Double(quantity) * price }
}

struct Position: Identifiable, Codable {
    var id: String { symbol }
    let symbol: String
    let quantity: Int
    let averagePrice: Double
    let currentPrice: Double

    var marketValue: Double { Double(quantity) * currentPrice }
    var unrealizedPnL: Double { Double(quantity) * (currentPrice - averagePrice) }
}

struct Portfolio: Codable {
    let buyingPower: Double
    let marketValue: Double
    let totalPnL: Double
    let positions: [Position]

    static let empty = Portfolio(buyingPower: 0, marketValue: 0, totalPnL: 0, positions: [])
}

struct Quote: Codable {
    let symbol: String
    let last: Double
    let changePercent: Double

    static func placeholder(symbol: String) -> Quote {
        .init(symbol: symbol, last: 0, changePercent: 0)
    }
}

final class PortfolioStore: ObservableObject {
    @Published var portfolio: Portfolio = .empty
    @Published var openOrders: [TradeOrder] = []
    @Published var executions: [Execution] = []

    private var cancellables = Set<AnyCancellable>()

    func bind(to tradeService: TradeService) {
        tradeService.$portfolio
            .receive(on: DispatchQueue.main)
            .assign(to: &$portfolio)

        tradeService.$openOrders
            .receive(on: DispatchQueue.main)
            .assign(to: &$openOrders)

        tradeService.$executions
            .receive(on: DispatchQueue.main)
            .assign(to: &$executions)
    }
}

