final class MarketDataService: ObservableObject {
    @Published private(set) var quotes: [String: Quote] = [:]
    private var timer: AnyCancellable?

    func connect() {
        let symbols = ["AAPL", "MSFT", "NVDA", "TSLA", "AMZN", "META", "GOOGL"]
        symbols.forEach { symbol in
            quotes[symbol] = .init(symbol: symbol, last: Double.random(in: 100...500), changePercent: Double.random(in: -2...2))
        }

        timer = Timer.publish(every: 1.25, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self else { return }
                for symbol in symbols {
                    let current = self.quotes[symbol] ?? .placeholder(symbol: symbol)
                    let drift = Double.random(in: -1.4...1.4)
                    let next = max(1, current.last + drift)
                    let change = ((next - current.last) / max(current.last, 0.01)) * 100
                    self.quotes[symbol] = .init(symbol: symbol, last: next, changePercent: change)
                }
            }
    }

    func quote(for symbol: String) -> Quote {
        quotes[symbol] ?? .placeholder(symbol: symbol)
    }
}

actor RequestSigner {
    func headers(for request: URLRequest, apiKey: String, secret: String) -> [String: String] {
        let timestamp = String(Int(Date().timeIntervalSince1970))
        let method = request.httpMethod ?? "GET"
        let path = request.url?.path ?? "/"
        let body = String(data: request.httpBody ?? Data(), encoding: .utf8) ?? ""
        let payload = "\(timestamp)\(method)\(path)\(body)"
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        let signed = Data(signature).map { String(format: "%02hhx", $0) }.joined()

        return [
            "X-API-KEY": apiKey,
            "X-SIGNATURE": signed,
            "X-TIMESTAMP": timestamp,
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
    }
}

struct APIConfiguration {
    let baseURL: URL
    let apiKey: String
    let apiSecret: String
}

enum APIError: LocalizedError {
    case invalidResponse
    case unauthorized
    case server(String)
    case decoding
    case transport(String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid server response."
        case .unauthorized: return "Unauthorized request."
        case .server(let message): return message
        case .decoding: return "Unable to decode server response."
        case .transport(let message): return message
        }
    }
}

final class APIClient {
    let config: APIConfiguration
    private let session: URLSession
    private let signer = RequestSigner()
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder

    init(config: APIConfiguration, session: URLSession = .shared) {
        self.config = config
        self.session = session
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        self.decoder.dateDecodingStrategy = .iso8601
        self.encoder.dateEncodingStrategy = .iso8601
    }

    func send<T: Decodable, U: Encodable>(_ path: String, method: String, body: U? = nil) async throws -> T {
        let url = config.baseURL.appendingPathComponent(path)
        var request = URLRequest(url: url)
        request.httpMethod = method
        if let body {
            request.httpBody = try encoder.encode(body)
        }
        let headers = await signer.headers(for: request, apiKey: config.apiKey, secret: config.apiSecret)
        headers.forEach { request.setValue($1, forHTTPHeaderField: $0) }

        do {
            let (data, response) = try await session.data(for: request)
            guard let http = response as? HTTPURLResponse else { throw APIError.invalidResponse }

            switch http.statusCode {
            case 200...299:
                do {
                    return try decoder.decode(T.self, from: data)
                } catch {
                    throw APIError.decoding
                }
            case 401:
                throw APIError.unauthorized
            default:
                let message = String(data: data, encoding: .utf8) ?? "Server error."
                throw APIError.server(message)
            }
        } catch let error as APIError {
            throw error
        } catch {
            throw APIError.transport(error.localizedDescription)
        }
    }

    func sendNoBody<T: Decodable>(_ path: String, method: String = "GET") async throws -> T {
        struct EmptyBody: Encodable {}
        return try await send(path, method: method, body: Optional<EmptyBody>.none)
    }

    func delete(_ path: String) async throws {
        let url = config.baseURL.appendingPathComponent(path)
        var request = URLRequest(url: url)
        request.httpMethod = "DELETE"
        let headers = await signer.headers(for: request, apiKey: config.apiKey, secret: config.apiSecret)
        headers.forEach { request.setValue($1, forHTTPHeaderField: $0) }

        do {
            let (_, response) = try await session.data(for: request)
            guard let http = response as? HTTPURLResponse else { throw APIError.invalidResponse }
            guard 200...299 ~= http.statusCode else {
                if http.statusCode == 401 { throw APIError.unauthorized }
                throw APIError.server("Unable to cancel order.")
            }
        } catch let error as APIError {
            throw error
        } catch {
            throw APIError.transport(error.localizedDescription)
        }
    }
}

final class TradeService: ObservableObject {
    @Published private(set) var portfolio: Portfolio = .empty
    @Published private(set) var openOrders: [TradeOrder] = []
    @Published private(set) var executions: [Execution] = []

    private let api: APIClient

    init(api: APIClient) {
        self.api = api
    }

    @MainActor
    func loadPortfolio() async {
        do {
            let response: Portfolio = try await api.sendNoBody("v1/portfolio")
            self.portfolio = response
        } catch {
        }
    }

    @MainActor
    func loadOpenOrders() async {
        do {
            let response: [TradeOrder] = try await api.sendNoBody("v1/orders/open")
            self.openOrders = response.sorted { $0.createdAt > $1.createdAt }
        } catch {
        }
    }

    func placeOrder(_ request: OrderRequest) async throws {
        let order: TradeOrder = try await api.send("v1/orders", method: "POST", body: request)
        await MainActor.run {
            self.openOrders.insert(order, at: 0)
        }
        try await refreshAfterTrade()
    }

    func cancelOrder(id: String) async throws {
        try await api.delete("v1/orders/\(id)")
        await MainActor.run {
            self.openOrders.removeAll { $0.id == id }
        }
    }

    private func refreshAfterTrade() async throws {
        async let portfolioTask: Portfolio = api.sendNoBody("v1/portfolio")
        async let ordersTask: [TradeOrder] = api.sendNoBody("v1/orders/open")
        async let executionsTask: [Execution] = api.sendNoBody("v1/executions")

        let (portfolio, orders, executions) = try await (portfolioTask, ordersTask, executionsTask)

        await MainActor.run {
            self.portfolio = portfolio
            self.openOrders = orders.sorted { $0.createdAt > $1.createdAt }
            self.executions = executions.sorted { $0.timestamp > $1.timestamp }
        }
    }
}

extension Double {
    var currency: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }

    var signedPercent: String {
        String(format: "%@%.2f%%", self >= 0 ? "+" : "", self)
    }
}